  budget: string;
  message: string;
};

const readString = (value: unknown, fallback = ''): string => {
  return typeof value === 'string' ? value : fallback;
};

const readNumber = (value: unknown, fallback = 0): number => {
  if (typeof value === 'number') {
    return value;
  }

  if (typeof value === 'string') {
    const parsed = Number(value);
    const isValidNumber = Number.isFinite(parsed);
    return isValidNumber ? parsed : fallback;
  }

  return fallback;
};

const fetchNodes = async (url: string): Promise<RawNode[]> => {
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`Request failed for ${url}`);
  }

  const json = (await response.json()) as NodesResponse;
  const hasPayload = json.payload != null;
  const hasNodes = hasPayload && Array.isArray(json.payload.nodes);
  if (!hasNodes) {
    return [];
  }

  return json.payload.nodes;
};

const mapProjectNode = (node: RawNode): PortfolioProject => {
  const fields = node.fieldValues;

  return {
    id: node.id,
    title: readString(fields['/text'], 'Untitled Project'),
    type: readString(fields['/attributes/@pTyp1'], 'web'),
    status: readString(fields['/attributes/@pSta1'], 'draft'),
    tech: readString(fields['/attributes/@pTec1'], 'N/A'),
    url: readString(fields['/attributes/@pUrl1'], ''),
    impact: readString(fields['/attributes/@pImp1'], 'Impact not set yet.'),
    featured: readString(fields['/attributes/@pFea1'], 'no'),
  };
};

const mapCaseStudyNode = (node: RawNode): CaseStudy => {
  const fields = node.fieldValues;

  return {
    id: node.id,
    title: readString(fields['/text'], 'Untitled Case Study'),
    client: readString(fields['/attributes/@cCli1'], 'Unknown Client'),
    industry: readString(fields['/attributes/@cInd1'], 'general'),
    problem: readString(fields['/attributes/@cPro1'], 'Problem not documented.'),
    solution: readString(fields['/attributes/@cSol1'], 'Solution not documented.'),
    outcome: readString(fields['/attributes/@cRes1'], 'Outcome not documented.'),
    year: readNumber(fields['/attributes/@cYr01'], 2026),
    tags: readString(fields['/attributes/@cTag1'], ''),
  };
};

const mapTestimonialNode = (node: RawNode): Testimonial => {
  const fields = node.fieldValues;

  return {
    id: node.id,
    title: readString(fields['/text'], 'Client Testimonial'),
    name: readString(fields['/attributes/@tNam1'], 'Anonymous'),
    role: readString(fields['/attributes/@tRol1'], 'Team Member'),
    company: readString(fields['/attributes/@tCom1'], 'Unknown Company'),
    quote: readString(fields['/attributes/@tQte1'], 'No quote available.'),
    rating: readNumber(fields['/attributes/@tRat1'], 5),
    featured: readString(fields['/attributes/@tFea1'], 'standard'),
  };
};

const usePortfolioData = () => {
  const [projects, setProjects] = React.useState<PortfolioProject[]>([]);
  const [caseStudies, setCaseStudies] = React.useState<CaseStudy[]>([]);
  const [testimonials, setTestimonials] = React.useState<Testimonial[]>([]);
  const [isLoading, setIsLoading] = React.useState(true);
  const [errorText, setErrorText] = React.useState<string | null>(null);

  const refresh = React.useCallback(async () => {
    setIsLoading(true);
    setErrorText(null);

    try {
      const [projectNodes, caseStudyNodes, testimonialNodes] = await Promise.all([
        fetchNodes(PROJECTS_ENDPOINT),
        fetchNodes(CASE_STUDIES_ENDPOINT),
        fetchNodes(TESTIMONIALS_ENDPOINT),
      ]);

      setProjects(projectNodes.map(mapProjectNode));
      setCaseStudies(caseStudyNodes.map(mapCaseStudyNode));
      setTestimonials(testimonialNodes.map(mapTestimonialNode));
    } catch {
      setErrorText('Unable to load portfolio data right now. Please refresh.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  React.useEffect(() => {
    void refresh();
  }, [refresh]);

  return {
    projects,
    caseStudies,
    testimonials,
    isLoading,
    errorText,
    refresh,
  };
};

