const AgentChatPanel: React.FC<{ chat: ReturnType<typeof createAgentChat> }> = ({ chat }) => {
  const [inputText, setInputText] = React.useState('');
  const { messages, status, error, addToolApprovalResponse } = useChat({
    chat,
    id: chat.id,
  });

  const isSending = status === 'submitted' || status === 'streaming';
  const trimmedInput = inputText.trim();
  const canSend = trimmedInput.length > 0 && !isSending;
  const hasMessages = messages.length > 0;

  const scrollContainerRef = React.useRef<HTMLDivElement | null>(null);

  React.useEffect(() => {
    const container = scrollContainerRef.current;
    if (container != null) {
      container.scrollTop = container.scrollHeight;
    }
  }, [messages]);

  const handleSend = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    if (!canSend) {
      return;
    }

    await chat.sendMessage({
      id: ulid(),
      role: 'user',
      parts: [{ type: 'text', text: trimmedInput }],
    });

    setInputText('');
  };

  return (
    <div className="flex h-[30rem] flex-col">
      <div ref={scrollContainerRef} className="flex-1 overflow-y-auto rounded-md border">
        <div className="space-y-4 p-3">
          {!hasMessages && (
            <div className="space-y-3">
              <p className="text-sm text-muted-foreground">Try one of these prompts:</p>
              <div className="flex flex-wrap gap-2">
                {[
                  'Show me your best conversion case study.',
                  'Summarize portfolio strengths.',
                  'Help me shape my project scope.',
                ].map((suggestion) => (
                  <Button
                    key={suggestion}
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={() => setInputText(suggestion)}
                  >
                    {suggestion}
                  </Button>
                ))}
              </div>
            </div>
          )}

          {messages.map((message) => {
            const fromUser = message.role === 'user';
            const roleLabel = fromUser ? 'You' : 'Portfolio Narrator';
            const bubbleClass = fromUser
              ? 'ml-auto bg-primary text-primary-foreground'
              : 'mr-auto bg-muted text-foreground';

            return (
              <div key={message.id} className="space-y-2">
                <p className="text-xs text-muted-foreground">{roleLabel}</p>
                {message.parts.map((part, index) => {
                  const partKey = `${message.id}-${index}`;

                  if (part.type === 'text') {
                    return fromUser ? (
                      <div key={partKey} className={cn('max-w-[90%] rounded-lg px-3 py-2 text-sm', bubbleClass)}>
                        {part.text}
                      </div>
                    ) : (
                      <div key={partKey} className={cn('max-w-[90%] rounded-lg px-3 py-2 text-sm', bubbleClass)}>
                        <MessageResponse>{part.text}</MessageResponse>
                      </div>
                    );
                  }

                  if (isToolUIPart(part)) {
                    const isApprovalRequested = part.state === 'approval-requested';
                    const hasApproval = part.approval != null;
                    const canApprove = isApprovalRequested && hasApproval;

                    return (
                      <div key={partKey} className="max-w-[90%] rounded-lg border bg-card px-3 py-2 text-xs">
                        <p className="font-medium">Tool: {part.toolName}</p>
                        <p className="text-muted-foreground">State: {part.state}</p>
                        {canApprove && (
                          <div className="mt-2 flex gap-2">
                            <Button
                              type="button"
                              size="sm"
                              variant="outline"
                              onClick={() =>
                                addToolApprovalResponse({
                                  id: part.approval.id,
                                  approved: false,
                                })
                              }
                            >
                              Deny
                            </Button>
                            <Button
                              type="button"
                              size="sm"
                              onClick={() =>
                                addToolApprovalResponse({
                                  id: part.approval.id,
                                  approved: true,
                                })
                              }
                            >
                              Approve
                            </Button>
                          </div>
                        )}
                      </div>
                    );
                  }

                  return null;
                })}
              </div>
            );
          })}
        </div>
      </div>

      <form onSubmit={handleSend} className="mt-3 space-y-2">
        <Textarea
          placeholder="Ask Portfolio Narrator…"
          value={inputText}
          onChange={(event) => setInputText(event.target.value)}
          className="min-h-20"
        />
        <div className="flex items-center justify-between gap-2">
          <p className="text-xs text-muted-foreground">
            {error != null ? 'Chat error. Please try again.' : 'Connected to Portfolio Narrator'}
          </p>
          <Button type="submit" disabled={!canSend} className="gap-2">
            <Send className="size-4" />
            {isSending ? 'Sending…' : 'Send'}
          </Button>
        </div>
      </form>
    </div>
  );
};

const AgentChatDock: React.FC = () => {
  const [isOpen, setIsOpen] = React.useState(false);
  const [isStarting, setIsStarting] = React.useState(false);
  const [chatError, setChatError] = React.useState<string | null>(null);
  const [chat, setChat] = React.useState<ReturnType<typeof createAgentChat> | null>(null);

  const handleStart = React.useCallback(async () => {
    setIsStarting(true);
    setChatError(null);

    try {
      const conversation = await createConversation(AGENT_ID);
      const nextChat = createAgentChat(AGENT_ID, conversation.conversationId);
      setChat(nextChat);
    } catch {
      setChatError('Unable to start chat right now.');
    } finally {
      setIsStarting(false);
    }
  }, []);

  React.useEffect(() => {
    const shouldStart = isOpen && chat == null && !isStarting;
    if (shouldStart) {
      void handleStart();
    }
  }, [chat, handleStart, isOpen, isStarting]);

  const showPanel = isOpen;
  const hasChat = chat != null;

  return (
    <>
      <Button
        type="button"
        className="fixed right-4 bottom-4 z-50 gap-2 rounded-full shadow-lg"
        onClick={() => setIsOpen((prev) => !prev)}
      >
        <MessageSquare className="size-4" />
        {showPanel ? 'Close Chat' : 'Agent Chat'}
      </Button>

      {showPanel && (
        <Card className="fixed right-4 bottom-20 z-40 w-[min(96vw,28rem)] border-border/80 bg-background/95 shadow-2xl backdrop-blur">
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between gap-2">
              <div className="flex items-center gap-2">
                <Bot className="size-4 text-primary" />
                <CardTitle className="text-base">Portfolio Narrator</CardTitle>
              </div>
              <Button size="icon" variant="ghost" onClick={() => setIsOpen(false)} aria-label="Close">
                <X className="size-4" />
              </Button>
            </div>
            <CardDescription>
              Trained on your case studies. Ask for stories, outcomes, and fit.
            </CardDescription>
          </CardHeader>
          <CardContent>
            {!hasChat && (
              <div className="space-y-3">
                {isStarting && (
                  <>
                    <Skeleton className="h-5 w-2/3" />
                    <Skeleton className="h-5 w-full" />
                    <Skeleton className="h-5 w-4/5" />
                  </>
                )}
                {chatError != null && <p className="text-sm text-destructive">{chatError}</p>}
                {!isStarting && (
                  <Button type="button" onClick={handleStart}>
                    Start Chat
                  </Button>
                )}
              </div>
            )}

            {hasChat && chat != null && <AgentChatPanel chat={chat} />}
          </CardContent>
        </Card>
      )}
    </>
  );
};

const App: React.FC = () => {
  const { projects, caseStudies, testimonials, isLoading, errorText, refresh } = usePortfolioData();
  const [theme, setTheme] = React.useState<'dark' | 'light'>('dark');

  React.useEffect(() => {
    const saved = window.localStorage.getItem('portfolio-theme');
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
    const initialTheme = saved === 'light' || saved === 'dark' ? saved : prefersDark ? 'dark' : 'light';
    const nextTheme = initialTheme as 'dark' | 'light';
    setTheme(nextTheme);
  }, []);

  React.useEffect(() => {
    const root = document.documentElement;
    const shouldUseDark = theme === 'dark';
    if (shouldUseDark) {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    window.localStorage.setItem('portfolio-theme', theme);
  }, [theme]);

  const featuredProjects = React.useMemo(() => {
    const featured = projects.filter((project) => project.featured === 'yes');
    const hasFeatured = featured.length > 0;
    return hasFeatured ? featured : projects;
